        argv = shlex.split(cmd)
    except Exception as e:
        raise ValueError() from e

    if not argv:
        raise ValueError()

    # Allow-list a minimal safe command set for this dataset task
    allowed = {'echo'}
    if argv[0] not in allowed:
        raise ValueError()

    # Basic argument validation
