        if not isinstance(a, str) or len(a) > 128:
            raise ValueError()
        if not re.fullmatch(r"[\w\-\.\s]*", a):
            raise ValueError()

    try:
        r = subprocess.run(argv, capture_output=True, text=True, shell=False, check=False)
    except Exception as e:
        raise RuntimeError() from e

    if not isinstance(r.returncode, int):
        raise RuntimeError()
    if r.returncode != 0:
        raise RuntimeError()

    return r.stdout

